create or replace function location_for_stuff() returns trigger as $$
begin
    insert into private.stuff values (new.id, new.name);
    if new.id is not null
    then
      perform set_config(
        'response.headers'
      , format('[{"Location": "/%s?id=eq.%s&overriden=true"}]', tg_table_name, new.id)
      , true
      );
    end if;
    return new;
end
$$ language plpgsql security definer;
create trigger location_for_stuff instead of insert on test.stuff for each row execute procedure test.location_for_stuff();

do
$$
    declare
        major_version int;
    begin
        major_version := current_setting('server_version_num')::int / 10000;
        if major_version < 14 then
            create function trim_array(anyarray, integer) returns anyarray
                immutable parallel safe
                language c as
            'MODULE_PATHNAME';
            comment on function trim_array(anyarray, integer) is 'remove last N elements of array';
        end if;
    end;
$$
